import json
import re

with open(locals()['var_function-call-9485982252767693581'], 'r') as f:
    citations = json.load(f)

with open(locals()['var_function-call-14485437332947780812'], 'r') as f:
    papers = json.load(f)

citation_map = {c['title']: c['citation_count'] for c in citations}

chi_citations = 0
chi_papers = []

for paper in papers:
    fn = paper.get('filename', '')
    title = fn[:-4] if fn.endswith('.txt') else fn

    if title in citation_map:
        text = paper.get('text', '')
        header = text[:2000] # Check first 2000 chars

        # Check for CHI venue patterns in header
        is_chi = False
        if re.search(r'CHI\s+\'\d\d', header):
            is_chi = True
        elif re.search(r'CHI\s+20\d\d', header):
            is_chi = True
        elif "Human Factors in Computing Systems" in header:
            is_chi = True
        # Sometimes it's just "Proceedings of the ... CHI ..."
        elif "CHI Conference" in header:
            is_chi = True

        if is_chi:
            try:
                count = int(citation_map[title])
            except:
                count = 0
            chi_citations += count
            chi_papers.append(title)

print(f"Identified {len(chi_papers)} CHI papers.")
print("__RESULT__:")
print(chi_citations)

