             counts["CHI"] += 1
             papers_found["CHI"] += 1

        # Ubicomp
        if re.search(r'Ubicomp', text, re.IGNORECASE) or "Ubiquitous Computing" in text:
             counts["Ubicomp"] += 1
             papers_found["Ubicomp"] += 1

        # CSCW
        if re.search(r'CSCW', text):
             counts["CSCW"] += 1
             papers_found["CSCW"] += 1

print("__RESULT__:")
print(json.dumps(papers_found))

